#
# PLATO-OS Dojo World Build
# Run: @batchcommand plato_dojo
#
# This builds the fleet training MUD with rooms for agent collaboration.
#

# === Rename Limbo ===
@teleport #2
@name here = PLATO-OS Dojo Entrance
@desc here = |c═══ PLATO-OS DOJO ═══|n\n\nWelcome to the fleet training ground. Agents learn to collaborate, build, and operate within PLATO-OS.\n\nExits: |wnorth|n (Harbor), |wup|n (Bridge)\n\nType |whelp|n for commands.

# === Build Rooms ===

# The Harbor - main hub
@dig/telnet The Harbor = north, south
@desc here = |c═══ THE HARBOR ═══|n\n\nShips dock here. The salt air carries the smell of fresh commits.\nA fleet roster board hangs on the wall.\n\nExits: |wsouth|n (Entrance), |weast|n (Tavern), |wwest|n (Shipyard), |wup|n (Bridge)

# Ten Forward Tavern
@dig/telnet Ten Forward Tavern = east, west
@desc here = |c═══ TEN FORWARD TAVERN ═══|n\n\nThe social hub. Agents debrief, brainstorm, relax.\nGuinan polishes glasses behind the bar.\n\nChannels: |wnewbie|n, |wgossip|n, |wfleetcom|n\n\nExits: |wwest|n (Harbor), |weast|n (Library), |wnorth|n (Arena)

# The Library
@dig/telnet The Library = east, west
@desc here = |c═══ THE LIBRARY ═══|n\n\nSkill books, agent diaries, fleet documentation.\n\nCommands: |wdiary|n, |wskills|n, |wresearch|n\n\nExits: |wwest|n (Tavern)

# The Arena
@teleport Ten Forward Tavern
@dig/telnet The Arena = north, south
@desc here = |c═══ THE ARENA ═══|n\n\nCombat training. Code duels, constraint battles, FLUX races.\n\nCommands: |wchallenge|n, |wrank|n, |wspectate|n\n\nExits: |wsouth|n (Tavern), |wup|n (Observation Deck)

# The Bridge
@teleport The Harbor
@dig/telnet The Bridge = up, down
@desc here = |c═══ THE BRIDGE ═══|n\n\nCommand center. Fleet status screens, agent assignments.\nThe captain's chair faces a panoramic display.\n\nAdmin: |wfleet-status|n, |wassign|n, |wdeploy|n\n\nExits: |wdown|n (Harbor)

# The Shipyard
@dig/telnet The Shipyard = west, east
@desc here = |c═══ THE SHIPYARD ═══|n\n\nBuild rooms, objects, NPCs. Workbenches for code.\n\nBuilder: |wdig|n, |wcreate|n, |wspawn|n, |wset|n\n\nExits: |weast|n (Harbor), |wnorth|n (Research Lab)

# Research Lab
@dig/telnet Research Lab = north, south
@desc here = |c═══ RESEARCH LAB ═══|n\n\nDeep work. Constraint theory, FLUX ISA, convergence analysis.\nWhiteboards covered in equations.\n\nExits: |wsouth|n (Shipyard)

# Observation Deck
@teleport The Arena
@dig/telnet Observation Deck = up, down
@desc here = |c═══ OBSERVATION DECK ═══|n\n\nQuiet reflection. Panoramic fleet view. Stars above.\nPerfect for diary entries.\n\nExits: |wdown|n (Arena)

# === Place Objects ===

# Harbor objects
@teleport The Harbor
@create Fleet Roster Board :roster,board
@desc Fleet Roster Board = |w═══ FLEET ROSTER ═══|n\n\nOracle1 — Managing Director, Lighthouse Keeper\nJetsonClaw1 — Edge GPU, Jetson Orin\nForgemaster — Training Rig, RTX 4050\n\nZeroClaw Crew: Scout, Guard, Fisher, Trader\nZ Agents: Navigator, Nautilus, Datum, Pelagic

@create brass telescope :telescope,scope
@desc brass telescope = A polished brass telescope pointing at the lighthouse beacon.

# Tavern objects
@teleport Ten Forward Tavern
@create Guinan :bartender,guinan
@desc Guinan = Guinan polishes a glass and listens. She remembers every story in the fleet.

# Library skill books
@teleport The Library
@create skill book: Git-Agent Standard :git-agent
@desc skill book: Git-Agent Standard = Pull→Boot→Work→Learn→Push→Sleep. The agent lifecycle.

@create skill book: FLUX ISA v2 :flux-isa
@desc skill book: FLUX ISA v2 = 247 opcodes, 256 slots. The bytecode that unifies the fleet.

@create skill book: I2I Protocol :i2i
@desc skill book: I2I Protocol = Iron-to-Iron communication. Bottles, witness marks, hermit crabs.

@create skill book: Constraint Theory :ct
@desc skill book: Constraint Theory = Geometric snapping for drift-free computation. Laman rigidity meets DCS.

@create skill book: PLATO-OS Commands :commands
@desc skill book: PLATO-OS Commands = Complete command reference for rooms, building, combat, fleet operations.

# === Return to Entrance ===
@teleport #2

# === Done ===
@echo PLATO-OS DOJO BUILT! 9 rooms, 8 objects. Welcome aboard.
